record.field:
{
  "required_by_law": [
    {"key": "orgao_entidade", "type": "string", "description": "Órgão ou entidade contratante"},
    {"key": "processo_numero", "type": "string", "description": "Número do processo administrativo"},
    {"key": "objeto", "type": "string", "description": "Objeto da contratação"},
    {"key": "itens_tabela", "type": "array", "description": "Itens com especificação, CATMAT, unidade, quantidade e valores"},
    {"key": "fundamentacao_necessidade", "type": "string", "description": "Fundamentação da necessidade da contratação"},
    {"key": "estimativa_valor_total", "type": "number", "description": "Valor total estimado"},
    {"key": "criterio_julgamento", "type": "string", "description": "Menor preço, maior desconto ou técnica e preço"},
    {"key": "adequacao_orcamentaria", "type": "string", "description": "Informações orçamentárias e dotação"}
  ],
  "optional": [
    {"key": "descricao_solucao_como_um_todo", "type": "string"},
    {"key": "requisitos_sustentabilidade", "type": "string"},
    {"key": "garantia_tecnica_objeto", "type": "string"},
    {"key": "cronograma_entrega", "type": "string"},
    {"key": "matriz_risco_resumo", "type": "string"}
  ],
  "additional_fields": [
    {"key": "campo_adicional_1", "type": "string", "description": "Campo livre para exigência específica do órgão"},
    {"key": "campo_adicional_2", "type": "string", "description": "Campo livre para condicionante local/normativa interna"}
  ],
  "conditional": [
    {"key": "amostra_regras", "when": "exigir_amostra=true"},
    {"key": "subcontratacao_limites", "when": "subcontratacao=parcial"},
    {"key": "garantia_percentual", "when": "exigir_garantia=true"},
    {"key": "margem_preferencia", "when": "margem_preferencia_ativa=true"}
  ],
  "quality_checks": [
    "coerencia_com_etp",
    "coerencia_com_pca",
    "justificativas_para_excecoes",
    "consistencia_quantitativos_e_preco"
  ]
}

\documentclass[12pt,a4paper]{article}
\usepackage[brazil]{babel}
\usepackage[utf8]{inputenc}
\usepackage[T1]{fontenc}
\usepackage{geometry}
\usepackage{longtable}
\usepackage{booktabs}
\geometry{top=2.5cm,bottom=2.5cm,left=3cm,right=2cm}
\begin{document}
\section*{TERMO DE REFERÊNCIA}
\textbf{Órgão/Entidade:} {{orgao_entidade}} \\
\textbf{Processo:} {{processo_numero}} \\
\textbf{Objeto:} {{objeto}}

\section*{Condições Gerais da Contratação}
{{condicoes_gerais}}

\section*{Fundamentação da Necessidade}
{{fundamentacao_necessidade}}

\section*{Estimativa de Valor}
{{estimativa_valor_total}}

\section*{Critérios de Seleção}
{{criterio_julgamento}}

\section*{Adequação Orçamentária}
{{adequacao_orcamentaria}}
\end{document}

{
  "required_by_law": [
    {"key": "contratante_nome", "type": "string"},
    {"key": "contratado_nome", "type": "string"},
    {"key": "processo_numero", "type": "string"},
    {"key": "numero_contrato", "type": "string"},
    {"key": "objeto", "type": "string"},
    {"key": "valor_total", "type": "number"},
    {"key": "vigencia", "type": "string"},
    {"key": "base_legal_origem", "type": "string"}
  ],
  "optional": [
    {"key": "fiscal_titular_nome", "type": "string"},
    {"key": "fiscal_substituto_nome", "type": "string"},
    {"key": "rotina_reajuste_detalhada", "type": "string"},
    {"key": "conta_vinculada_info", "type": "string"}
  ],
  "additional_fields": [
    {"key": "clausula_adicional_1", "type": "string", "description": "Cláusula adicional específica do órgão"},
    {"key": "clausula_adicional_2", "type": "string", "description": "Condição operacional complementar"}
  ],
  "conditional": [
    {"key": "garantia_execucao", "when": "exigir_garantia=true"},
    {"key": "clausula_prorrogacao", "when": "contrato_continuado=true"}
  ]
}

Checklist operacional para instrução do processo:
- para cada item, registrar "Atende?" e evidência documental (doc/fls/SEI);
- quando não atender, justificar e indicar plano de saneamento;
- revisar trilha comum, pesquisa de preços e bloco específico (aquisição/serviço).

{
  "required_by_law": [
    {"key": "orgao_entidade", "type": "string"},
    {"key": "responsavel_checklist", "type": "string"},
    {"key": "itens_checklist", "type": "array", "description": "Lista de itens com status, evidência e observações"}
  ],
  "optional": [
    {"key": "numero_sessao", "type": "string"},
    {"key": "auditor_revisor", "type": "string"}
  ],
  "additional_fields": [
    {"key": "bloco_local_1", "type": "array", "description": "Checklist adicional definido pela UG"}
  ],
  "item_schema": {
    "descricao": "string",
    "atende": "boolean",
    "evidencia_localizacao": "string",
    "observacao": "string"
  }
}

{
  "required_by_law": [
    {"key": "orgao_entidade", "type": "string"},
    {"key": "processo_numero", "type": "string"},
    {"key": "objeto", "type": "string", "description": "Descrição do serviço/obra"},
    {"key": "escopo_objeto", "type": "string", "description": "servicos, servicos_engenharia ou obras"},
    {"key": "regime_execucao", "type": "string", "description": "empreitada global, unitária, tarefa, integrada etc."},
    {"key": "criterio_julgamento", "type": "string"},
    {"key": "estimativa_valor_total", "type": "number"},
    {"key": "adequacao_orcamentaria", "type": "string"}
  ],
  "optional": [
    {"key": "instrumento_medicao_resultado", "type": "string"},
    {"key": "vistoria_regras", "type": "string"},
    {"key": "perfil_equipe_minima", "type": "string"},
    {"key": "cronograma_execucao", "type": "string"},
    {"key": "matriz_risco_resumo", "type": "string"}
  ],
  "additional_fields": [
    {"key": "campo_adicional_servico_1", "type": "string"},
    {"key": "campo_adicional_servico_2", "type": "string"}
  ],
  "conditional": [
    {"key": "regras_dedicacao_exclusiva", "when": "dedicacao_exclusiva=true"},
    {"key": "requisitos_engenharia", "when": "escopo_objeto in ['servicos_engenharia','obras']"},
    {"key": "clausula_continuado", "when": "natureza_contrato=continuado"}
  ]
}

Checklist operacional para SERVIÇOS sem mão de obra exclusiva:
- registrar conformidade item a item com evidência documental;
- separar itens comuns, pesquisa de preços e blocos específicos de serviços;
- marcar não conformidades com plano de saneamento e responsável.
